const payload = $input.first().json;
const body = payload.body ?? payload;

const title = String(body.title ?? 'Site Record').trim();
const text = String(body.text ?? body.message_body ?? '').trim();
const source = String(body.source ?? 'site-record').trim();
const imageUrl = String(body.image_url ?? '').trim();

if (!text) {
  throw new Error('text vazio no payload Teams outbound');
}

const card = {
  '@type': 'MessageCard',
  '@context': 'http://schema.org/extensions',
  themeColor: '0076D7',
  summary: title,
  sections: [
    {
      activityTitle: title,
      activitySubtitle: source,
      text: text.replace(/\n/g, '<br>'),
    },
  ],
};

if (imageUrl) {
  card.sections[0].images = [{ image: imageUrl }];
}

const teamsWebhook = $env.TEAMS_INCOMING_WEBHOOK_URL;
if (!teamsWebhook) {
  throw new Error('Defina TEAMS_INCOMING_WEBHOOK_URL no n8n (Incoming Webhook do canal Teams)');
}

return [{ json: { teams_webhook_url: teamsWebhook, card } }];
